import sys
def main():
 data=list(map(int,sys.stdin.read().strip().split()))
 if not data:
  return
 idx=0
 T=data[idx];idx+=1
 out=[]
 for _ in range(T):
  n=data[idx];idx+=1
  maxLen=cur=0
  for _ in range(n):
   x=data[idx];idx+=1
   if x==0:
    cur=0
   else:
    cur+=1
   if cur>maxLen:
    maxLen=cur
  out.append(str(maxLen))
 sys.stdout.write('\n'.join(out))
if __name__=='__main__':
 main()

